class Solution:
    def maxCandies(self, status, candies, keys, containedBoxes, initialBoxes) -> int:
        from collections import deque
        has_key = set(i for i, s in enumerate(status) if s == 1)
        has_box = set(initialBoxes)
        queue = deque(b for b in initialBoxes if b in has_key)
        opened = set(queue)
        total = 0
        while queue:
            box = queue.popleft()
            total += candies[box]
            for k in keys[box]:
                if k not in has_key:
                    has_key.add(k)
                    if k in has_box and k not in opened:
                        opened.add(k)
                        queue.append(k)
            for b in containedBoxes[box]:
                has_box.add(b)
                if b in has_key and b not in opened:
                    opened.add(b)
                    queue.append(b)
        return total

