var maxCandies = function(status, candies, keys, containedBoxes, initialBoxes) {
    const hasKey = new Set(status.map((s, i) => s === 1 ? i : -1).filter(x => x >= 0));
    const hasBox = new Set(initialBoxes);
    const opened = new Set();
    const queue = [];
    let qi = 0;
    for (const b of initialBoxes) {
        if (hasKey.has(b)) { opened.add(b); queue.push(b); }
    }
    let total = 0;
    while (qi < queue.length) {
        const box = queue[qi++];
        total += candies[box];
        for (const k of keys[box]) {
            if (!hasKey.has(k)) {
                hasKey.add(k);
                if (hasBox.has(k) && !opened.has(k)) {
                    opened.add(k); queue.push(k);
                }
            }
        }
        for (const b of containedBoxes[box]) {
            hasBox.add(b);
            if (hasKey.has(b) && !opened.has(b)) {
                opened.add(b); queue.push(b);
            }
        }
    }
    return total;
};
